urlset:
{%- for file in pages -%}
    {% if not file.page.is_link and (file.page.abs_url or file.page.canonical_url) %}

         {% if file.page.canonical_url %}{{ file.page.canonical_url|e }}{% else %}{{ file.page.abs_url|e }}{% endif %}
         {% set iso = file.page.meta.git_revision_date_localized_raw_iso_datetime if file.page.meta else None %}
         {% if iso %}{{ iso|replace(" ", "T") }}Z{% elif file.page.update_date %}{{ file.page.update_date }}{% endif %}

    {%- endif -%}
{% endfor %}
